function questionTextHtml(value){
  let text=String(value??"").replace(/\r/g,"").trim();
  if(!text)return "";
  if(!/【[a-d]】/i.test(text)){
    text=text.replace(/([。！？])\s*([ａ-ｄa-d])\s+(?=[^\n])/g,(m,p,label)=>`${p}\n\n【${label.normalize("NFKC").toLowerCase()}】 `);
  }
  const parts=text.split(/\n{2,}/).map(x=>x.trim()).filter(Boolean);
  const html=[];
  for(const part of parts){
    const m=part.match(/^【([a-d])】\s*([\s\S]*)$/i);
    if(m){
      html.push(`<div class="statementBlock"><span class="statementLabel">${esc(m[1].toLowerCase())}</span><div class="statementText">${esc(m[2]).replace(/\n/g,"<br>")}</div></div>`);
    }else{
      html.push(`<div class="questionPrompt">${esc(part).replace(/\n/g,"<br>")}</div>`);
    }
  }
  return html.join("");
}
