function choiceId(c,i){return String((typeof c==="string"?i+1:(c.id??i+1)))}
function answerLabel(q){if(!hasChoices(q))return answerOf(q);let hit=q.choices.slice(0,5).find((c,i)=>choiceId(c,i)===answerOf(q));return hit?`${answerOf(q)}. ${choiceText(hit)}`:answerOf(q)}
function loadHiddenBuiltin(){try{let x=JSON.parse(localStorage.getItem(HIDDEN_BUILTIN)||"null");return x&&Array.isArray(x.exams)&&x.sets&&typeof x.sets==="object"?x:{exams:[],sets:{}}}catch(e){return {exams:[],sets:{}}}}function saveHiddenBuiltin(){localStorage.setItem(HIDDEN_BUILTIN,JSON.stringify(hiddenBuiltin));const saved=loadHiddenBuiltin();if(JSON.stringify(saved)!==JSON.stringify(hiddenBuiltin))throw new Error("削除状態を端末へ保存できませんでした") }function save(){localStorage.setItem(STORE,JSON.stringify(store))}function saveC(){localStorage.setItem(CUSTOM,JSON.stringify(custom))}function backupDeleteState(reason="削除前バックアップ"){localStorage.setItem(DELETE_BACKUP,JSON.stringify({savedAt:new Date().toISOString(),reason,customExams:custom,hiddenBuiltin,answers:store}))}function backupCustom(reason="削除前バックアップ"){backupDeleteState(reason)}function visibleBuiltinExams(){return builtinExams.filter(e=>!hiddenBuiltin.exams.includes(e.id)).map(e=>{let hiddenSets=new Set(hiddenBuiltin.sets[e.id]||[]),copy=JSON.parse(JSON.stringify(e));copy.sets=(copy.sets||[]).filter(s=>!hiddenSets.has(s.id));return copy}).filter(e=>(e.sets||[]).length)}function emptyExam(){return normalizeExam({id:"__empty__",title:"問題なし",date:"",category:activeCategory,category_label:catLabel(activeCategory),_systemEmpty:true,sets:[{id:"__empty__-set-1",title:"問題なし",note:"問題を追加してください",questions:[]}]})}function realExams(){return (data.exams||[]).filter(e=>!e._systemEmpty)}function rebuildData(){let real=[...visibleBuiltinExams(),...custom].slice(0,100).map(normalizeExam);data.exams=real.length?real:[emptyExam()]}function toast(m="コピーしました"){
  const t=$("toast");
  if(!t)return;
  t.textContent=m;
  t.classList.remove("show");
  void t.offsetWidth;
  t.classList.add("show");
  clearTimeout(window.__toastTimer);
  window.__toastTimer=setTimeout(()=>t.classList.remove("show"),2600);
}function today(){return new Date().toLocaleDateString("ja-JP")}function iso(d=new Date()){return d.toISOString().slice(0,10)}function add(d,n){let x=new Date(d);x.setDate(x.getDate()+n);return x.toISOString().slice(0,10)}function categoryPlaceholder(){return normalizeExam({id:`__empty__-${activeCategory}`,title:"未登録",date:"",category:activeCategory,category_label:catLabel(activeCategory),_systemEmpty:true,sets:[{id:`__empty__-${activeCategory}-set`,title:"未登録",note:"このカテゴリの問題を追加してください",questions:[]}]})}
function exam(){return data.exams.find(e=>e.id===examId&&examCategory(e)===activeCategory)||categoryPlaceholder()}
function set(){let e=exam();return e.sets.find(se=>se.id===setId)||e.sets[0]||{id:"",title:"未登録",questions:[]}}
function qs(){return set().questions||[]}
function storeKey(e=examId,s=setId){let ex=data&&data.exams?data.exams.find(x=>x.id===e):null,cat=ex?examCategory(ex):activeCategory;return cat+"::"+e+"::"+s}
function legacyStoreKey(e=examId,s=setId){return e+"::"+s}
function arr(e=examId,s=setId){
  let ex=data.exams.find(x=>x.id===e)||data.exams[0],se=ex.sets.find(x=>x.id===s)||ex.sets[0],list=(se.questions||[]),n=list.length,k=storeKey(e,s),oldK=legacyStoreKey(e,s);
  if(!store[k]&&store[oldK]&&n>0){store[k]=JSON.parse(JSON.stringify(store[oldK]))}
  if(!store[k])store[k]={answers:Array(n).fill(""),confidence:Array(n).fill(false),graded:false,wrong:[],score:null,updated:null,review:[],manualFeedback:"",chatgptResult:null};
  if(store[k].answers.length!==n)store[k].answers=Array(n).fill("");
  if(!Array.isArray(store[k].confidence)||store[k].confidence.length!==n)store[k].confidence=Array(n).fill(false);
  store[k].answers=store[k].answers.map((v,i)=>isValidAnswer(list[i]||{},v)?v:"");
  if(n===0){store[k].answers=[];store[k].confidence=[];store[k].graded=false;store[k].wrong=[];store[k].score=null;store[k].review=[]}
  if(!store[k].review)store[k].review=[];
  return store[k]
}
function makeUniqueCustomId(e,used){let base=String(e.id||"custom");let cat=examCategory(e);let candidate=base;if(used.has(candidate)){candidate=`${base}-${cat.replaceAll("_","-")}`;let n=2;while(used.has(candidate))candidate=`${base}-${cat.replaceAll("_","-")}-${n++}`;}if(candidate!==e.id){let old=e.id;e.id=candidate;(e.sets||[]).forEach((s,i)=>{if(!s.id||String(s.id).startsWith(old+"-set-"))s.id=`${candidate}-set-${i+1}`});}used.add(candidate);return e;}
function migrateCustomIds(){let used=new Set((builtinExams||[]).map(e=>e.id));custom=(custom||[]).map(e=>normalizeExam(e)).map(e=>makeUniqueCustomId(e,used));saveC()}
function repairPersistentState(){
  let changed=false;
  if(!store||typeof store!=="object"||Array.isArray(store)){store={};changed=true}
  if(!Array.isArray(custom)){custom=[];changed=true}
  custom=custom.filter(e=>e&&typeof e==="object"&&e.id&&e.title).map(e=>{
    if(!Array.isArray(e.sets)){e.sets=[];changed=true}
    e.sets=e.sets.filter(s=>s&&typeof s==="object").map((s,i)=>{
      if(!s.id){s.id=`${e.id}-set-${i+1}`;changed=true}
      if(!s.title){s.title=`第${i+1}セット`;changed=true}
      if(!Array.isArray(s.questions)){s.questions=[];changed=true}
      s.questions=s.questions.filter(q=>q&&typeof q==="object"&&q.text);
      return s;
    }).filter(s=>s.questions.length>0);
    return normalizeExam(e);
  }).filter(e=>e.sets.length>0);

  const builtinMap=new Map((builtinExams||[]).map(e=>[e.id,e]));
  const validHiddenExams=(hiddenBuiltin.exams||[]).filter(id=>builtinMap.has(id));
  if(validHiddenExams.length!==(hiddenBuiltin.exams||[]).length)changed=true;
  const validHiddenSets={};
  Object.entries(hiddenBuiltin.sets||{}).forEach(([eid,sids])=>{
    const ex=builtinMap.get(eid);if(!ex){changed=true;return}
    const valid=new Set((ex.sets||[]).map(s=>s.id));
    const kept=(Array.isArray(sids)?sids:[]).filter(id=>valid.has(id));
    if(kept.length)validHiddenSets[eid]=kept;
    if(kept.length!==(Array.isArray(sids)?sids:[]).length)changed=true;
  });
  hiddenBuiltin={exams:validHiddenExams,sets:validHiddenSets};

  const validKeys=new Set();
  [...visibleBuiltinExams(),...custom].forEach(e=>(e.sets||[]).forEach(se=>{
    validKeys.add(`${examCategory(e)}::${e.id}::${se.id}`);
    validKeys.add(`${e.id}::${se.id}`);
  }));
  Object.keys(store).forEach(k=>{
    const st=store[k];
    if(!validKeys.has(k)||!st||typeof st!=="object"){delete store[k];changed=true;return}
    if(!Array.isArray(st.answers))st.answers=[];
    if(!Array.isArray(st.confidence))st.confidence=[];
    if(!Array.isArray(st.wrong))st.wrong=[];
    if(!Array.isArray(st.review))st.review=[];
  });
  if(changed){save();saveC();saveHiddenBuiltin()}
  return changed;
}
function manualRepair(){
  backupDeleteState("保存データ修復前");
  repairPersistentState();
  rebuildData();
  chooseSafeExam();
  selectors();
  render();
  toast("保存データを修復しました");
}

