function restoreSession(auto=false){const s=safeReadJson(SESSION_STORE,null);if(!s)return false;const ex=(data.exams||[]).find(e=>e.id===s.examId);const se=ex&&(ex.sets||[]).find(x=>x.id===s.setId);if(!ex||!se)return false;activeCategory=canonicalCategory(s.activeCategory||examCategory(ex));examId=s.examId;setId=s.setId;index=Math.max(0,Math.min(Number(s.index)||0,(se.questions||[]).length-1));view="normal";viewList=null;selectors();const tab=document.querySelector(`[data-tab="${s.tab||'solve'}"]`)||document.querySelector('[data-tab="solve"]');if(tab)tab.click();render();setTimeout(()=>window.scrollTo(0,Number(s.scrollY)||0),50);if(!auto)toast("前回の続きから再開しました");return true}
