async function boot(){
  $("login").classList.add("hidden");$("app").classList.remove("hidden");
  try{
    try{const r=await fetch(DATA_URL,{cache:"no-store"});if(!r.ok)throw new Error(`questions.json ${r.status}`);data=await r.json()}catch(e){console.warn("外部DB読込失敗。内蔵データへ切替",e);data=EMBED}
    data=JSON.parse(JSON.stringify(data||EMBED));
    if(!data.meta)data.meta=JSON.parse(JSON.stringify(EMBED.meta));
    if(!Array.isArray(data.meta.examDates))data.meta.examDates=[];
    if(!Array.isArray(data.exams))data.exams=[];
    builtinExams=JSON.parse(JSON.stringify(data.exams||[])).filter(e=>e&&e.id).map(normalizeExam);
    repairPersistentState();
    migrateCustomIds();
    rebuildData();
    let latest=[...categoryExams()].sort((a,b)=>(b.date||"").localeCompare(a.date||""))[0]||categoryPlaceholder();
    if(!latest||!Array.isArray(latest.sets)||!latest.sets.length)latest=emptyExam();
    examId=latest.id;setId=((latest.sets.find(s=>Array.isArray(s.questions)&&s.questions.length)||latest.sets[0])||{}).id||"";
    $("sub").textContent=(data.meta.appName||"登録販売者 試験対策")+" "+APP_VERSION+" / Build "+BUILD_DATE;
    if($("appVersion"))$("appVersion").textContent=APP_VERSION;if($("appBuild"))$("appBuild").textContent=BUILD_DATE;
    selectors();bind();render();
    if(lastSession&&sessionLabel()){$("resumeCard")?.classList.remove("hidden");if($("resumeLabel"))$("resumeLabel").textContent=sessionLabel();}
  }catch(e){
    console.error(e);
    alert(`読み込み失敗\n${e&&e.message?e.message:"保存データの不整合が考えられます"}\n\n「データ」タブ →「問題データ管理」→「保存データを修復」を実行してください。`);
  }
}
