function normal(){view="normal";viewList=null;$("searchBox").value=""}function vqs(){return view==="normal"||!viewList?qs().map((q,i)=>({q,i})):viewList}function weakList(){let w=[];data.exams.forEach(e=>e.sets.forEach(s=>{let st=arr(e.id,s.id),list=s.questions||[];if(st.graded)st.wrong.forEach(i=>list[i]&&w.push({q:list[i],i}))}));return w.length?w:qs().map((q,i)=>({q,i}))}function searchList(term){term=(term||"").trim();if(!term)return qs().map((q,i)=>({q,i}));return qs().map((q,i)=>({q,i})).filter(x=>(x.q.text+x.q.chapter+x.q.source+shortExplanationOf(x.q)).includes(term))}
