function home(){let e=exam(),s=set(),a=0,t=0;e.sets.forEach(st=>{let x=arr(e.id,st.id).answers;a+=x.filter(Boolean).length;t+=x.length});$("todayLabel").textContent=`${examOptionLabel(e)}｜${s.title}`;$("todayProgress").textContent=a+"/"+t;$("countdown").innerHTML=data.meta.examDates.map(x=>{const d=Math.ceil((new Date(x.date)-new Date())/86400000);return `<div class="countdownItem"><span>${esc(x.label)}</span><strong>${d}</strong><small>日</small></div>`}).join("");let first=new Date("2026-07-02"),last=new Date("2026-09-06"),now=new Date();$("examProgress").textContent="学習期間進捗："+Math.max(0,Math.min(100,Math.round((now-first)/(last-first)*100)))+"%";if($("streak"))$("streak").textContent=`連続${streak()}日`;let st=arr(),u=st.answers.filter(x=>!x).length;let status=t===0?"問題未登録":a===0?"未開始":a<t?`学習中（残り${t-a}問）`:st.graded?`完了・採点済み（不正解${st.wrong.length}問）`:"回答完了・未採点";if($("todayExecutionStatus"))$("todayExecutionStatus").textContent=status;$("nextAction").innerHTML=u?`未回答が <b>${u}</b> 問あります。`:st.graded?`自己採点済み。不正解 ${st.wrong.length} 問。`:"回答済み。採点へ。"}
function setQuestionOffset(){
  const e=exam(),se=set();
  const setIndex=Math.max(0,(e.sets||[]).findIndex(x=>x.id===se.id));
  return (e.sets||[]).slice(0,setIndex).reduce((sum,x)=>sum+((x.questions||[]).length),0);
}
function displayedQuestionNumber(listIndex,item){
  const offset=setQuestionOffset();
  const localNo=Number(item?.q?.no);
  // 通し番号を持つJSONはその番号を優先。各セットで1から振り直されている場合だけ前セット分を加算する。
  if(Number.isFinite(localNo)&&localNo>offset)return localNo;
  return offset+listIndex+1;
}
function jumpWindow(list){
  const size=30;
  const start=Math.floor(index/size)*size;
  return list.slice(start,start+size).map((item,localIndex)=>({item,listIndex:start+localIndex}));
}
