function question(){
  let e=exam(),se=set(),list=vqs();
  if($("currentSelectionLabel"))$("currentSelectionLabel").textContent=`${catLabel(activeCategory)}｜${examOptionLabel(e)}｜${se.title||"問題なし"}`;
  $("empty").classList.toggle("hidden",list.length>0);$("questionCard").classList.toggle("hidden",!list.length);
  if(!list.length){$("qProgress").textContent="0/0";$("unanswered").textContent="未回答 0";$("questionCard").innerHTML="";$("jumpGrid").innerHTML="";return;}
  if(index>=list.length)index=list.length-1;
  let it=list[index],q=it.q,i=it.i,st=arr(),ans=st.answers[i],show=st.graded&&!examMode,unsure=!!st.confidence[i];
  $("qProgress").textContent=`${index+1}/${list.length}`;$("unanswered").textContent=`未回答 ${st.answers.filter(x=>!x).length}`;
  let meta=[q.chapter,q.source||q.question_type||"",view].filter(Boolean).join(" / "),choicesHtml="";
  if(hasChoices(q)){choicesHtml=`<div class="choices examChoices">${q.choices.slice(0,5).map((c,ci)=>{let id=choiceId(c,ci),txt=choiceText(c);return `<button class="choice examChoice ${ans===id?"selected":""}" data-v="${esc(id)}"><span class="choiceId">${esc(id)}</span><span class="choiceText">${choiceTextHtml(txt)}</span></button>`}).join("")}</div>`}else{choicesHtml=`<div class="choices"><button class="choice ok ${ans==="○"?"selected":""}" data-v="○">○</button><button class="choice ng ${ans==="×"?"selected":""}" data-v="×">×</button></div>`}
  const confidenceHtml=`<div class="confidenceRow"><button id="confidenceBtn" class="confidenceBtn ${unsure?"active":""}" type="button">${unsure?"✓ 迷った":"迷った"}</button><span>${unsure?"後で見直す印を付けています":"自信がない時だけ記録"}</span></div>`;
  const resultHtml=show?`<button id="openSolveExplanationBtn" class="result resultSummaryButton" type="button"><div><b>${isCorrectAnswer(q,ans)?"正解":"不正解"}</b><span>あなた：${esc(ans||"未回答")}　正答：${esc(answerLabel(q))}</span><p>${esc(shortExplanationOf(q))}</p></div><strong>詳細 ›</strong></button>`:"";
  $("questionCard").innerHTML=`<div class="qTop"><div><div class="qNo">問${displayedQuestionNumber(index,it)}</div><div class="badge">${esc(meta)}</div></div><div class="badge">${exam().date||""}</div></div><div class="qText">${questionTextHtml(q.text)}</div>${choicesHtml}${confidenceHtml}${resultHtml}`;
  document.querySelectorAll(".choice").forEach(b=>b.onclick=()=>{st.answers[i]=b.dataset.v;st.updated=new Date().toISOString();save();render()});
  if($("confidenceBtn"))$("confidenceBtn").onclick=()=>{st.confidence[i]=!st.confidence[i];st.updated=new Date().toISOString();save();render();toast(st.confidence[i]?"迷った問題として記録しました":"迷った印を外しました")};
  if($("openSolveExplanationBtn"))$("openSolveExplanationBtn").onclick=openSolveExplanation;
  $("jumpGrid").innerHTML=jumpWindow(list).map(({item:x,listIndex:j})=>{let c=st.answers[x.i]?"answered":"";if(show)c=isCorrectAnswer(x.q,st.answers[x.i])?"correct":"wrong";if(st.confidence[x.i])c+=" unsure";if(j===index)c+=" current";const shownNo=displayedQuestionNumber(j,x);return `<button class="jump ${c}" data-i="${j}">${shownNo}<br>${st.answers[x.i]||"未"}${st.confidence[x.i]?" ?":""}</button>`}).join("");
  document.querySelectorAll(".jump").forEach(b=>b.onclick=()=>{index=+b.dataset.i;render()})
}
function grade(){let st=arr(),c=0,w=[],chapterResults={};qs().forEach((q,i)=>{const ok=isCorrectAnswer(q,st.answers[i]);if(ok)c++;else w.push(i);chapterResults[q.chapter]??={correct:0,total:0,rate:0};chapterResults[q.chapter].total++;if(ok)chapterResults[q.chapter].correct++});Object.values(chapterResults).forEach(v=>v.rate=v.total?Math.round(v.correct/v.total*100):0);st.graded=true;st.wrong=w;st.score={correct:c,total:qs().length,rate:qs().length?Math.round(c/qs().length*100):0};st.questionResults=qs().map((q,i)=>({no:q.no,chapter:q.chapter,knowledgeId:q.knowledge_id||q.knowledgeId||"",userAnswer:st.answers[i]||"",correctAnswer:answerOf(q),isCorrect:isCorrectAnswer(q,st.answers[i]),wasUnsure:!!st.confidence[i]}));st.wrongQuestions=w.map(i=>{const q=qs()[i],key=`${examId}|${setId}|${q.no}`;const m=wrongMeta[key]||{};return {no:q.no,chapter:q.chapter,knowledgeId:q.knowledge_id||q.knowledgeId||"",source:q.source||"",text:q.text,userAnswer:st.answers[i]||"",correctAnswer:answerOf(q),shortExplanation:shortExplanationOf(q),explanation:"",wasUnsure:!!st.confidence[i],reviewed:!!m.reviewed,reviewCount:m.reviewCount||0}});st.reviewStatus={completed:st.wrongQuestions.every(x=>x.reviewed),reviewedAt:null,remainingWrongCount:st.wrongQuestions.filter(x=>!x.reviewed).length};st.retryResults=st.retryResults||[];st.chapterResults=chapterResults;st.schemaVersion="1.1";st.gradedAt=new Date().toISOString();st.updated=new Date().toISOString();st.review=w.flatMap(i=>[3,7,14].map(d=>({q:i,due:add(new Date(),d),interval:d,done:false})));save()}
function all(){let total=0,correct=0,unsure=0,ch={},weak={},hist=[];data.exams.forEach(e=>e.sets.forEach(s=>{let st=arr(e.id,s.id),list=s.questions||[];if(st.graded&&st.score){total+=st.score.total;correct+=st.score.correct;unsure+=(st.confidence||[]).filter(Boolean).length;hist.push({label:e.title+s.title,rate:st.score.rate});list.forEach((q,i)=>{ch[q.chapter]??={c:0,t:0,w:0};ch[q.chapter].t++;if(isCorrectAnswer(q,st.answers[i]))ch[q.chapter].c++;else{ch[q.chapter].w++;weak[q.chapter]=(weak[q.chapter]||0)+1}})}}));return {total,correct,unsure,ch,weak,hist,rate:total?Math.round(correct/total*100):0}}
function stats(){let s=all();$("statsBox").innerHTML=`<div class="statRow"><b>累計</b><span>${s.total}問</span><span>${s.rate}%</span></div><div class="statRow"><b>迷った問題</b><span></span><span>${s.unsure}問</span></div>`+["第1章","第2章","第3章","第4章","第5章"].map(k=>{let v=s.ch[k]||{c:0,t:0};return `<div class="statRow"><b>${k}</b><span>${v.c}/${v.t}</span><span>${v.t?Math.round(v.c/v.t*100):0}%</span></div>`}).join("")}
function bar(label,rate){return `<div class="barRow"><span>${esc(label).slice(0,8)}</span><div class="barTrack"><div class="barFill ${rate<70?"bad":rate<80?"warn":""}" style="width:${rate}%"></div></div><span>${rate}%</span></div>`}function graphs(){let s=all();$("rateGraph").innerHTML=s.hist.length?s.hist.slice(-10).map(h=>bar(h.label,h.rate)).join(""):"採点後に表示";$("chapterGraph").innerHTML=["第1章","第2章","第3章","第4章","第5章"].map(k=>{let v=s.ch[k]||{c:0,t:0};return bar(k,v.t?Math.round(v.c/v.t*100):0)}).join("");let r=Object.entries(s.weak).sort((a,b)=>b[1]-a[1]);$("weakRanking").innerHTML=r.length?r.map((x,i)=>`<div class="rankItem"><b>${i+1}位 ${x[0]}</b><br>誤答数：${x[1]}</div>`).join(""):"苦手データなし"}
function radar(){let c=$("radarCanvas"),ctx=c.getContext("2d"),s=all(),labs=["第1章","第2章","第3章","第4章","第5章"],cx=160,cy=160,r=110;ctx.clearRect(0,0,320,320);ctx.strokeStyle="#ddd";ctx.fillStyle="#111827";ctx.font="13px sans-serif";for(let ring=1;ring<=5;ring++){ctx.beginPath();labs.forEach((l,i)=>{let a=-Math.PI/2+i*2*Math.PI/5,rr=r*ring/5,x=cx+Math.cos(a)*rr,y=cy+Math.sin(a)*rr;i?ctx.lineTo(x,y):ctx.moveTo(x,y)});ctx.closePath();ctx.stroke()}ctx.beginPath();labs.forEach((l,i)=>{let v=s.ch[l]||{c:0,t:0},rate=v.t?v.c/v.t:0,a=-Math.PI/2+i*2*Math.PI/5,rr=r*rate,x=cx+Math.cos(a)*rr,y=cy+Math.sin(a)*rr;i?ctx.lineTo(x,y):ctx.moveTo(x,y)});ctx.closePath();ctx.fillStyle="rgba(17,24,39,.25)";ctx.fill();ctx.strokeStyle="#111827";ctx.stroke();labs.forEach((l,i)=>{let a=-Math.PI/2+i*2*Math.PI/5,x=cx+Math.cos(a)*(r+24),y=cy+Math.sin(a)*(r+24);ctx.fillStyle="#111827";ctx.fillText(l,x-18,y)})}
function feedback(){let st=arr(),s=all();if(!st.graded)return"現在のセットは未採点です。";let imp=st.chatgptResult;let danger=imp?.dangerKnowledge||Object.entries(s.weak).sort((a,b)=>b[1]-a[1])[0]?.[0]||"大きな偏りなし";let extra=imp?`\n\n【ChatGPT取り込み講評】\n${imp.feedback||""}${imp.nextTasks?`\n\n次回タスク：${imp.nextTasks}`:""}`:"";return`登録販売者 学習フィードバック\n日付：${exam().date||today()}\n${exam().title} ${set().title}\n\n今回正答率：${st.score.rate}%（${st.score.correct}/${st.score.total}）\n累計正答率：${s.rate}%（${s.correct}/${s.total}）\n今日一番危ない知識：${danger}\n次にやること：間違えた問題を3日後・7日後・14日後に復習。${extra}`}
function calendar(){let done=new Set();Object.values(store).forEach(st=>st.updated&&done.add(st.updated.slice(0,10)));let html="";for(let i=27;i>=0;i--){let d=new Date();d.setDate(d.getDate()-i);let x=iso(d);html+=`<div class="dayCell ${done.has(x)?"done":""} ${x===iso()?"today":""}">${d.getMonth()+1}/${d.getDate()}</div>`}$("studyCalendar").innerHTML=html}function streak(){let done=new Set();Object.values(store).forEach(st=>st.updated&&done.add(st.updated.slice(0,10)));let n=0,d=new Date();while(done.has(iso(d))){n++;d.setDate(d.getDate()-1)}return n}
function dueItems(){let items=[];data.exams.forEach(e=>e.sets.forEach(s=>{let st=arr(e.id,s.id),list=s.questions||[];(st.review||[]).forEach(r=>list[r.q]&&items.push({e,s,r,q:list[r.q]}))}));return items.sort((a,b)=>a.r.due.localeCompare(b.r.due))}function reviews(){const items=dueItems(),box=$("reviewSchedule");if(!box)return;if(!items.length){box.innerHTML=`<p class="reviewEmpty">復習予定なし</p>`;return;}const groups=[];items.slice(0,30).forEach(x=>{let g=groups.find(v=>v.date===x.r.due);if(!g){g={date:x.r.due,items:[]};groups.push(g)}g.items.push(x)});box.innerHTML=`<div class="reviewScheduleCompact">${groups.map(g=>`<div class="reviewDateRow"><div class="reviewDateLabel"><b>${esc(g.date)}</b><span>${g.items.length}問</span></div><div class="reviewDueChips">${g.items.slice(0,8).map(x=>`<span class="reviewDueChip">${esc(x.s.title)} 問${esc(x.q.no)}</span>`).join("")}${g.items.length>8?`<span class="reviewDueMore">+${g.items.length-8}</span>`:""}</div></div>`).join("")}</div>${items.length>30?`<p class="reviewMoreNote">ほか${items.length-30}件</p>`:""}`;}function dueNotice(){let due=dueItems().filter(x=>x.r.due<=iso());$("dueNotice").classList.toggle("hidden",!due.length);$("dueNotice").innerHTML=due.length?`<b>復習通知</b><br>今日までに復習すべき問題が ${due.length} 問あります。分析 → 復習予定を確認してください。`:""}
