function ans(allset=false){let e=exam();return allset?["【登録販売者 解答】",`日付：${e.date||today()}`,`${e.title} 全セット`,...e.sets.map(s=>`${s.title}：${arr(e.id,s.id).answers.map(x=>x||"未").join("")}`)].join("\n"):`【登録販売者 解答】\n日付：${e.date||today()}\n${e.title} ${set().title}\n回答：${arr().answers.map(x=>x||"未").join("")}`}function promptCurrent(){return ans(false)+"\n\n今回の正答率、累計正答率、章別正答率、今日一番危ない知識、間違えた問題の短い解説を出してください。"}function promptAll(){return ans(true)+"\n\n120問の総括、章別分析、改善点、翌日の重点学習項目を出してください。"}
function buildResultPayload(){const e=exam(),s=set(),st=arr();const questions=(s.questions||[]).map((q,i)=>({no:q.no,chapter:q.chapter,knowledgeId:q.knowledge_id||q.knowledgeId||"",source:q.source||"",text:q.text,choices:q.choices||[],userAnswer:st.answers[i]||"",correctAnswer:answerOf(q),shortExplanation:shortExplanationOf(q),explanation:""}));return {type:"touhan_submission",schemaVersion:"1.2",date:e.date||today(),examId:e.id,setId:s.id,examTitle:e.title,setTitle:s.title,category:examCategory(e),generatedAt:new Date().toISOString(),answers:st.answers.map(x=>x||""),questions,instruction:"このJSONだけを使って採点してください。今回正答率、累計正答率（過去データが無ければ今回のみ）、章別正答率、今日一番危ない知識を示してください。最後に、必ずアプリへそのまま読み込める採点結果JSONを1つだけコードブロックで出力してください。採点結果JSONには type=touhan_result、schemaVersion、date、examId、setId、gradedAt、score、chapterResults、questionResults、wrongNumbers、wrongQuestions、reviewStatus、retryResults を含めてください。questionResultsは全問題分を出力し、各項目に no、chapter、knowledgeId、source、text、userAnswer、correctAnswer、isCorrect、shortExplanation、explanation を含めてください。shortExplanationは正誤判定の根拠となる知識を1〜3行で、explanationは『正しい知識』『この記述のどこが正しい／誤っているか』『混同しやすい点・例外』を具体的に説明してください。「公式過去問に基づく」「主語・条件・例外を確認」のような一般論だけで済ませないでください。wrongQuestionsにも同じ解説項目を含め、reviewed=false、reviewCount=0を付けてください。"}}

