function reviewExplanations(x){const st=arr(x.e.id,x.s.id);const imported=(st.wrongQuestions||[]).find(w=>String(w.no)===String(x.q.no));const detail=detailedFor(x.e,x.s,x.q);const short=effectiveShortExplanation(x.e,x.s,x.q,imported?.shortExplanation||"");return {short,detail};}
