function themeLabelFromQuestion(q){
  const explicit=String(q?.theme||q?.knowledgeTheme||q?.knowledge_name||"").trim();if(explicit)return explicit;
  const t=String(q?.text||"").replace(/\s+/g," ");
  const patterns=[
    [/アセトアミノフェン/,"アセトアミノフェンの使用条件"],[/アスピリン|サリチル酸/,"アスピリンとライ症候群"],[/イブプロフェン/,"イブプロフェンの使用条件"],
    [/解熱鎮痛/,"解熱鎮痛薬"],[/抗ヒスタミン|クロルフェニラミン|ジフェンヒドラミン/,"抗ヒスタミン成分"],[/交感神経刺激|プソイドエフェドリン|メチルエフェドリン/,"交感神経刺激成分"],
    [/制酸|炭酸水素ナトリウム|酸化マグネシウム/,"制酸成分の違い"],[/瀉下|センノシド|ビサコジル|便秘/,"瀉下成分と便秘薬"],[/止瀉|ロペラミド/,"止瀉成分"],
    [/添付文書/,"添付文書の読み方"],[/副作用被害救済/,"医薬品副作用被害救済制度"],[/副作用等報告|報告制度/,"副作用等報告制度"],[/要指導医薬品/,"要指導医薬品の販売"],
    [/第一類医薬品/,"第一類医薬品の販売"],[/指定第二類医薬品/,"指定第二類医薬品"],[/登録販売者/,"登録販売者の業務"],[/広告|誇大/,"医薬品広告の規制"],
    [/プリオン/,"プリオン"],[/HDL|LDL/,"HDL・LDLと動脈硬化"],[/香蘇散/,"香蘇散"],[/漢方/,"漢方処方の適応"]
  ];
  for(const [re,label] of patterns)if(re.test(t))return label;
  const key=String(q?.knowledge_id||q?.knowledgeId||"");
  if(key)return `${q?.chapter||"知識"}の要点 ${key.split(/[-_:]/).slice(-1)[0]}`;
  return t.replace(/[。．].*$/,'').slice(0,28)||"知識テーマ";
}
function collectReviewKnowledge(){
  const map=new Map();
  (data?.exams||[]).forEach(e=>(e.sets||[]).forEach(s=>{const st=arr(e.id,s.id),list=s.questions||[];list.forEach((q,i)=>{const wrong=st.graded&&(st.wrong||[]).includes(i),unsure=!!st.confidence?.[i];if(!wrong&&!unsure)return;const chapter=q.chapter||"章不明",theme=themeLabelFromQuestion(q),k=`${chapter}|${theme}`;if(!map.has(k))map.set(k,{key:k,chapter,theme,wrongCount:0,unsureCount:0,lastWrongAt:"",questions:[]});const x=map.get(k);if(wrong)x.wrongCount++;if(unsure)x.unsureCount++;const at=st.gradedAt||st.updated||e.date||"";if(wrong&&at>x.lastWrongAt)x.lastWrongAt=at;x.questions.push({e,s,q,index:i,userAnswer:st.answers?.[i]||"",wrong,unsure,at});})}));
  return [...map.values()];
}
function priorityStars(x){let score=x.wrongCount*2+x.unsureCount;const recent=x.lastWrongAt&&((Date.now()-new Date(x.lastWrongAt).getTime())/86400000<=7);if(recent)score+=2;return Math.max(1,Math.min(5,score>=7?5:score>=5?4:score>=3?3:score>=2?2:1));}
function stars(n){return "★★★★★".slice(0,n)+"☆☆☆☆☆".slice(0,5-n)}
function openKnowledgeReview(){knowledgeReviewView={level:"chapters",chapter:"",theme:"",scroll:0};renderKnowledgeReview();const p=$("knowledgeReviewPage");p.classList.remove("hidden");p.setAttribute("aria-hidden","false");document.body.classList.add("reviewDetailOpen");p.scrollTop=0}
