function renderKnowledgeReview(){const all=collectReviewKnowledge(),body=$("knowledgeReviewBody");if(!body)return;if(knowledgeReviewView.level==="chapters"){const chapters=["第1章","第2章","第3章","第4章","第5章","章不明"].map(ch=>({chapter:ch,items:all.filter(x=>x.chapter===ch)})).filter(x=>x.items.length);$("knowledgeReviewTitle").textContent="知識テーマ別復習";$("knowledgeReviewMeta").textContent=`要復習 ${all.length}項目`;body.innerHTML=chapters.length?chapters.map(g=>`<button class="card wrongGroupButton" data-knowledge-chapter="${esc(g.chapter)}"><div><b>${esc(g.chapter)}</b><div class="note">要復習 ${g.items.length}項目</div></div><span class="wrongGroupChevron">›</span></button>`).join(""):"<div class='card'>復習対象の知識はありません。</div>";return}
  const items=all.filter(x=>x.chapter===knowledgeReviewView.chapter).sort((a,b)=>priorityStars(b)-priorityStars(a)||b.wrongCount-a.wrongCount);
  if(knowledgeReviewView.level==="themes"){$("knowledgeReviewTitle").textContent=knowledgeReviewView.chapter;$("knowledgeReviewMeta").textContent=`要復習 ${items.length}項目`;body.innerHTML=items.map(x=>`<button class="card knowledgeThemeButton" data-knowledge-theme="${esc(x.key)}"><div class="knowledgeThemeHead"><b>${esc(x.theme)}</b><span class="priorityStars" aria-label="復習優先度${priorityStars(x)}">${stars(priorityStars(x))}</span></div><div class="note">誤答${x.wrongCount}回・迷った${x.unsureCount}回・関連${x.questions.length}問</div><span class="knowledgeThemeChevron">詳細を見る ›</span></button>`).join("");return}
  const x=all.find(v=>v.key===knowledgeReviewView.theme);if(!x)return;$("knowledgeReviewTitle").textContent=x.theme;$("knowledgeReviewMeta").textContent=`優先度 ${stars(priorityStars(x))}｜関連${x.questions.length}問`;body.innerHTML=`<div class="card knowledgeSummaryCard"><div class="priorityStars large">${stars(priorityStars(x))}</div><div class="note">誤答${x.wrongCount}回・迷った${x.unsureCount}回</div></div>`+x.questions.sort((a,b)=>String(b.at).localeCompare(String(a.at))).map(v=>`<button class="card reviewQuestionSummary" data-knowledge-question="${esc(v.e.id)}|${esc(v.s.id)}|${esc(v.q.no)}"><div class="homeCardHead"><b>${esc(v.e.date||"日付なし")} 問${esc(v.q.no)}</b><span class="categoryBadge">${esc(v.q.chapter||"")}</span></div><div class="reviewQuestionText">${questionTextHtml(v.q.text)}</div><div class="reviewCompactAnswers"><span>あなた ${esc(v.userAnswer||"未回答")}</span><span>正答 ${esc(answerOf(v.q))}</span>${v.unsure?'<span class="unsureMark">迷った</span>':''}</div><strong>問題詳細を見る ›</strong></button>`).join("")}
function knowledgeReviewBack(){if(knowledgeReviewView.level==="detail"){knowledgeReviewView.level="themes";renderKnowledgeReview();return}if(knowledgeReviewView.level==="themes"){knowledgeReviewView.level="chapters";knowledgeReviewView.chapter="";renderKnowledgeReview();return}closeKnowledgeReview()}
