function normalizeImportedExam(o){
  if(o.exam)o=o.exam;
  if(!Array.isArray(o.sets)&&Array.isArray(o.questions)){
    o.sets=[{id:(o.id||"custom")+"-set-1",title:o.setTitle||"第1セット",note:o.note||"",questions:o.questions}];
    delete o.questions;
  }
  if(!o.id||!o.title||!Array.isArray(o.sets))throw 0;
  if(!o.date)o.date=today();
  if(!o.category)o.category=$("importCategorySelect")?$("importCategorySelect").value:"one_by_one";
  if(!o.category_label)o.category_label=catLabel(o.category);
  o.sets.forEach((se,si)=>{se.id=se.id||`${o.id}-set-${si+1}`;se.questions=se.questions||[];if(!se.title)se.title=o.category==="one_by_one"?`第${si+1}セット`:si===0?"前半":si===1?"後半":`区分${si+1}`;});
  return normalizeExam(o);
}
