function isCustomExam(id){return custom.some(e=>e.id===id)}
function storedSetInfo(e,s){let k=storeKey(e.id,s.id),lk=legacyStoreKey(e.id,s.id),st=store[k]||store[lk],n=(s.questions||[]).length;return {answered:st&&Array.isArray(st.answers)?st.answers.filter(Boolean).length:0,total:n,graded:!!(st&&st.graded),hasHistory:!!st}}
function removeStoreForSet(e,s){delete store[storeKey(e.id,s.id)];delete store[legacyStoreKey(e.id,s.id)]}
function chooseSafeExam(){let list=categoryExams();let first=list[0]||data.exams[0];if(first){examId=first.id;setId=(first.sets[0]||{}).id||"";index=0}else{examId="";setId="";index=0}}
function isSampleExam(e){return String(e.title||"").includes("サンプル")||String(e.id||"").includes("sample")||String(e.category||"")==="sample"}
function examQuestionCount(e){return (e.sets||[]).reduce((a,s)=>a+((s.questions||[]).length),0)}
function examSearchText(e){return [e.date,e.title,e.id,examCategory(e),...(e.sets||[]).flatMap(s=>[s.title,s.id,s.note])].join(" ").toLowerCase()}
function filteredManageExams(){
  let q=(manageSearch||"").trim().toLowerCase();
  let list=[...data.exams].filter(e=>{
    if(e._systemEmpty)return false;
    let customFlag=isCustomExam(e.id),cat=examCategory(e),sample=isSampleExam(e);
    if(manageFilter==="custom"&&!customFlag)return false;
    if(manageFilter==="official"&&customFlag)return false;
    if(manageFilter==="one_by_one"&&cat!=="one_by_one")return false;
    if(manageFilter==="exam_style"&&cat!=="exam_style")return false;
    if(manageFilter==="practice60"&&cat!=="practice60")return false;
    if(manageFilter==="sample"&&!sample)return false;
    if(q&&!examSearchText(e).includes(q))return false;
    return true;
  });
  list.sort((a,b)=>{
    if(manageSort==="old")return String(a.date||"").localeCompare(String(b.date||""));
    if(manageSort==="title")return String(a.title||"").localeCompare(String(b.title||""),'ja');
    if(manageSort==="questions")return examQuestionCount(b)-examQuestionCount(a);
    return String(b.date||"").localeCompare(String(a.date||""));
  });
  return list;
}
