function confirmTypedDelete(message,word){if(!confirm(message))return false;return prompt(`確認のため「${word}」と入力してください。`)===word;}
function manageClick(ev){
  let b=ev.target.closest("button[data-action]");if(!b)return;
  let action=b.dataset.action,eid=b.dataset.exam,sid=b.dataset.set;
  let e=data.exams.find(x=>x.id===eid);if(!e)return;
  if(action==="clear-set"){let se=(e.sets||[]).find(x=>x.id===sid);if(!se)return;if(confirm(`${e.title} ${se.title} の回答履歴だけ削除しますか？\n問題データは残ります。`)){removeStoreForSet(e,se);save();render();toast("回答履歴を削除しました")}return;}
  let customFlag=isCustomExam(eid);
  if(action==="delete-set"){
    let se=(e.sets||[]).find(x=>x.id===sid);if(!se)return;
    let label=`${e.title} ${se.title}`;
    if(!confirmTypedDelete(`${label} の問題だけを削除します。\n他のセット・他の回は削除されません。\n回答履歴も同時に削除されます。`,`セット削除`))return;
    backupDeleteState("セット削除前");removeStoreForSet(e,se);
    if(customFlag){let ci=custom.findIndex(x=>x.id===eid),si=(custom[ci].sets||[]).findIndex(x=>x.id===sid);if(ci<0||si<0)return;custom[ci].sets.splice(si,1);if(!custom[ci].sets.length)custom.splice(ci,1);saveC();}
    else{let list=hiddenBuiltin.sets[eid]||[];if(!list.includes(sid))list.push(sid);hiddenBuiltin.sets[eid]=list;let original=builtinExams.find(x=>x.id===eid);if(original&&(original.sets||[]).every(x=>list.includes(x.id))){if(!hiddenBuiltin.exams.includes(eid))hiddenBuiltin.exams.push(eid);delete hiddenBuiltin.sets[eid]}saveHiddenBuiltin();}
    save();rebuildData();chooseSafeExam();selectors();refreshManageUi(`${label} を削除しました`);return;
  }
  if(action==="delete-exam"){
    let label=`${e.title}（${catLabel(examCategory(e))}・全${examQuestionCount(e)}問）`;
    if(!confirmTypedDelete(`${label} だけを削除します。\n他の回は残ります。\nこの回の回答履歴も削除されます。`,`この回を削除`))return;
    backupDeleteState("回削除前");(e.sets||[]).forEach(se=>removeStoreForSet(e,se));
    if(customFlag){let ci=custom.findIndex(x=>x.id===eid);if(ci>=0)custom.splice(ci,1);saveC();}
    else{if(!hiddenBuiltin.exams.includes(eid))hiddenBuiltin.exams.push(eid);delete hiddenBuiltin.sets[eid];saveHiddenBuiltin();}
    save();rebuildData();chooseSafeExam();selectors();refreshManageUi(`${label} を削除しました`);return;
  }
}
