function openTimerStart(sec,wm,label){
  pendingTimerStart={sec,wm,label};
  let min=Math.round(sec/60),total=wm?weakList().length:(label==="120問"?120:(vqs().length||qs().length||30));
  if($("timerStartText"))$("timerStartText").innerHTML=`問題数：<b>${total}</b>問<br>制限時間：<b>${min}</b>分<br>この内容でタイマーを開始しますか？`;
  if($("timerStartMinutes"))$("timerStartMinutes").value=min;
  if($("timerCountdown")){ $("timerCountdown").classList.add("hidden"); $("timerCountdown").textContent="3"; }
  if($("timerStartModal"))$("timerStartModal").classList.remove("hidden");
}
function closeTimerStart(){pendingTimerStart=null;if($("timerStartModal"))$("timerStartModal").classList.add("hidden")}
function confirmTimerStart(){
  if(!pendingTimerStart)return;
  let m=Number($("timerStartMinutes")?$("timerStartMinutes").value:0);
  if(!m||m<1){toast("制限時間を入力してください");return;}
  let sec=Math.round(m*60),wm=pendingTimerStart.wm,label=pendingTimerStart.label;
  if($("timerCountdown"))$("timerCountdown").classList.remove("hidden");
  let n=3;
  let run=()=>{
    if(!$("timerCountdown")){closeTimerStart();startTimer(sec,wm,label);return;}
    $("timerCountdown").textContent=n>0?String(n):"開始";
    if(n-->=0)setTimeout(run,650);
    else{closeTimerStart();startTimer(sec,wm,label)}
  };
  run();
}
