function renderTimerPanels(){
  let rem=currentRemaining(),a=data?timerAnswered():{answered:0,total:30},status=timerState.running?"実行中":(examMode?"一時停止中":"停止中");
  document.querySelectorAll(".timerDisplay").forEach(x=>x.textContent=fmt(rem));
  document.querySelectorAll(".timerStatus").forEach(x=>x.textContent=status);
  document.querySelectorAll(".timerModeLabel").forEach(x=>x.textContent=timerState.mode||"30問");
  document.querySelectorAll(".timerAnswered").forEach(x=>x.textContent=`回答 ${a.answered}/${a.total}`);
  document.querySelectorAll(".timerPanel").forEach(p=>{p.classList.toggle("running",timerState.running);p.classList.toggle("paused",examMode&&!timerState.running);p.classList.toggle("finished",rem<=0&&!timerState.running)});
  document.querySelectorAll('[data-timer-panel="solve"]').forEach(p=>p.classList.toggle("hidden",!timerState.visible));
  if($("timerShowCard"))$("timerShowCard").classList.toggle("hidden",timerState.visible);
}
function startTimerLoop(){if(timer)clearInterval(timer);timer=setInterval(()=>{let before=timerState.remaining,rem=currentRemaining();renderTimerPanels();if(before>0&&rem<=0&&!timerState.timeUpNotified){timerState.timeUpNotified=true;saveTimer();toast("時間切れです");setTimeout(()=>{if(confirm("時間切れです。提出して自己採点しますか？"))finish();else{examMode=false;saveTimer();render()}},100)}} ,1000)}
function startTimer(sec,wm,label){wrongMock=wm;if(wm){view="weak";viewList=weakList();index=0}examMode=true;timerState={mode:label||"30問",duration:sec,remaining:sec,running:true,endAt:Date.now()+sec*1000,wrongMock:wm,timeUpNotified:false,visible:true};saveTimer();document.querySelector('[data-tab="solve"]').click();startTimerLoop();render()}
function pauseTimer(){if(!examMode&&!timerState.running)return;currentRemaining();timerState.running=false;timerState.endAt=null;saveTimer();renderTimerPanels();toast("一時停止しました")}
function resumeTimer(){if(timerState.remaining<=0)return;if(!examMode)examMode=true;timerState.running=true;timerState.endAt=Date.now()+timerState.remaining*1000;saveTimer();startTimerLoop();renderTimerPanels();toast("再開しました")}
function resetTimer(){if(!confirm("タイマーをリセットしますか？"))return;if(timer)clearInterval(timer);timerState={...defaultTimerState()};examMode=false;wrongMock=false;saveTimer();render();toast("リセットしました")}
function hideTimer(){timerState.visible=false;saveTimer();renderTimerPanels();toast("タイマーを非表示にしました")}
function showTimer(){timerState.visible=true;saveTimer();renderTimerPanels();toast("タイマーを表示しました")}
function finish(){if(timer)clearInterval(timer);currentRemaining();timerState.running=false;timerState.endAt=null;saveTimer();examMode=false;wrongMock=false;grade();render();toast("自己採点しました")}
function shuffle(a){return [...a].sort(()=>Math.random()-0.5)}function copy(t){return navigator.clipboard.writeText(t).then(()=>toast()).catch(()=>toast("コピー失敗"))}

function importResultJson(){
  try{
    let raw=$("resultImportBox").value.trim();
    if(!raw) return toast("JSONを貼り付けてください");
    let r=JSON.parse(raw);
    if(r.type && r.type!=="touhan_result") throw 0;
    let eId=r.examId||examId, sId=r.setId||setId;
    let ex=data.exams.find(e=>e.id===eId); if(!ex) throw 0;
    let se=ex.sets.find(s=>s.id===sId); if(!se) throw 0;
    let st=arr(eId,sId);
    const importedQuestions=se.questions||[];
    if(typeof r.answerString==="string"){
      st.answers=r.answerString.split("").map((x,i)=>isValidAnswer(importedQuestions[i]||{},x)?x:"");
    }else if(Array.isArray(r.answers)){
      st.answers=r.answers.map((x,i)=>isValidAnswer(importedQuestions[i]||{},String(x||""))?String(x||""):"");
    }
    let total=(se.questions||[]).length||st.answers.length||0;
    let wrong=Array.isArray(r.wrongNumbers)?r.wrongNumbers.map(n=>Number(n)-1).filter(i=>i>=0):[];
    if(!wrong.length && se.questions && se.questions.length){
      wrong=[];
      se.questions.forEach((q,i)=>{ if(!isCorrectAnswer(q,st.answers[i])) wrong.push(i); });
    }
    let correct=typeof r.correct==="number"?r.correct:total-wrong.length;
    st.graded=true;
    st.wrong=wrong;
    st.score={correct,total,rate:typeof r.rate==="number"?r.rate:(total?Math.round(correct/total*100):0)};
    st.schemaVersion=r.schemaVersion||"1.1";st.gradedAt=r.gradedAt||new Date().toISOString();st.questionResults=r.questionResults||st.questionResults||[];st.wrongQuestions=r.wrongQuestions||st.wrongQuestions||[];st.reviewStatus=r.reviewStatus||st.reviewStatus||null;st.retryResults=r.retryResults||st.retryResults||[];st.chapterResults=r.chapterResults||st.chapterResults||null;
    if(Array.isArray(r.questionResults)){r.questionResults.forEach(item=>{const q=(se.questions||[]).find(x=>String(x.no)===String(item.no));if(!q)return;if(item.shortExplanation&&!isGenericExplanation(item.shortExplanation))q.shortExplanation=item.shortExplanation;if(item.explanation&&!isGenericExplanation(item.explanation))q.explanation=item.explanation;});saveC();}
    if(Array.isArray(r.wrongQuestions)){r.wrongQuestions.forEach(item=>{const q=(se.questions||[]).find(x=>String(x.no)===String(item.no));if(!q)return;if(item.shortExplanation&&!isGenericExplanation(item.shortExplanation))q.shortExplanation=item.shortExplanation;if(item.explanation&&!isGenericExplanation(item.explanation))q.explanation=item.explanation;});saveC();}
    st.chatgptResult={
      importedAt:new Date().toISOString(),
      date:r.date||ex.date||today(),
      cumulativeRate:r.cumulativeRate??null,
      chapterRates:r.chapterRates||null,
      dangerKnowledge:r.dangerKnowledge||"",
      feedback:r.feedback||"",
      nextTasks:r.nextTasks||"",
      raw:r
    };
    st.manualFeedback=[r.feedback||"",r.dangerKnowledge?("今日一番危ない知識："+r.dangerKnowledge):"",r.nextTasks?("次回タスク："+r.nextTasks):""].filter(Boolean).join("\n\n");
    st.updated=new Date().toISOString();
    st.review=wrong.flatMap(i=>[3,7,14].map(d=>({q:i,due:add(new Date(),d),interval:d,done:false})));
    save();
    examId=eId; setId=sId; index=0;
    selectors(); render();
    toast("採点結果を取り込みました");
  }catch(e){
    alert("採点結果JSONの形式が正しくありません。");
  }
}
function copyResultTemplate(){
  let st=arr();
  let tpl={
    type:"touhan_result",
    date: exam().date || today(),
    examId: examId,
    setId: setId,
    examTitle: exam().title,
    setTitle: set().title,
    answerString: st.answers.map(x=>x||"未").join(""),
    answers: st.answers.map(x=>x||""),
    correct: 0,
    total: (qs()||[]).length || 0,
    rate: 0,
    cumulativeRate: 0,
    chapterRates:{"第1章":0,"第2章":0,"第3章":0,"第4章":0,"第5章":0},
    wrongNumbers:[],
    dangerKnowledge:"ここに今日一番危ない知識",
    feedback:"ここに採点講評",
    nextTasks:"ここに次回の復習・重点項目"
  };
  copy(JSON.stringify(tpl,null,2));
}

if(localStorage.getItem(LOGIN)==="ok")boot();
if("serviceWorker" in navigator){
  window.addEventListener("load",async()=>{
    try{
      const reg=await navigator.serviceWorker.register("./service-worker.js?v=13.4.0",{updateViaCache:"none"});
      await reg.update();
      if(reg.waiting){reg.waiting.postMessage({type:"SKIP_WAITING"});}
      navigator.serviceWorker.addEventListener("controllerchange",()=>{if(!window.__swReloaded){window.__swReloaded=true;location.reload();}});
    }catch(e){console.warn("Service Worker registration failed",e)}
  });
}
